import React from 'react';
import Card from '../components/Card';
import { Chart as C, LineElement, CategoryScale, LinearScale, PointElement } from 'chart.js';
import { Line } from 'react-chartjs-2';

C.register(LineElement, CategoryScale, LinearScale, PointElement);

const Dashboard = ()=>{
  const savingsData = {
    labels:['Jan','Feb','Mar','Apr','May','Jun'],
    datasets:[{label:'Amount ($)',data:[3000,5500,6200,8000,9200,11000],borderColor:'#34d399',tension:0.3}]
  };

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:12}}>
        <h3>Admin Dashboard</h3>
      </div>
      <div className="card-row">
        <Card title="Total Members" value="1,245" />
        <Card title="Total Staff" value="24" />
        <Card title="Total Savings" value="$125,450" />
        <Card title="Total Loans" value="$78,300" />
        <Card title="Pending Requests" value="23" />
      </div>

      <div style={{display:'grid',gridTemplateColumns:'1fr 420px',gap:16}}>
        <div className="card">
          <h4 style={{marginTop:0}}>Savings Growth</h4>
          <Line data={savingsData} />
        </div>
        <div className="card">
          <h4 style={{marginTop:0}}>Loan Distribution</h4>
          <div style={{height:220,display:'flex',alignItems:'center',justifyContent:'center',color:'var(--muted)'}}>Bar chart placeholder</div>
        </div>
      </div>

      <div style={{marginTop:16}} className="card">
        <h4 style={{marginTop:0}}>Recent Activity</h4>
        <div className="small-muted">New member registered — John Doe</div>
        <div className="small-muted">Loan approved — Jane Smith</div>
        <div className="small-muted">Savings deposit — Mike Johnson</div>
      </div>

    </div>
  );
}
export default Dashboard;
